mapper.delete:
DELETE FROM diet_record
WHERE id = #{id}
  AND user_id = #{userId}

mapper.select:
SELECT COUNT(1)
FROM diet_record
WHERE user_id = #{userId}

    AND record_date >= #{startDate}


    AND record_date <= #{endDate}

SELECT id, user_id, meal_type, record_date, total_calories, total_protein, total_fat, total_carb,
       remark, created_at, updated_at
FROM diet_record
WHERE user_id = #{userId}

    AND record_date >= #{startDate}


    AND record_date <= #{endDate}

ORDER BY record_date DESC, id DESC
LIMIT #{size} OFFSET #{offset}

SELECT id, diet_record_id, food_item_id, food_name, intake_gram, calories, protein, fat, carb, created_at FROM diet_record_item WHERE diet_record_id IN
#{recordId}
ORDER BY id ASC

SELECT
    COUNT(1) AS record_count,
    COALESCE(SUM(total_calories), 0) AS total_calories,
    COALESCE(SUM(total_protein), 0) AS total_protein,
    COALESCE(SUM(total_fat), 0) AS total_fat,
    COALESCE(SUM(total_carb), 0) AS total_carb
FROM diet_record
WHERE user_id = #{userId}
  AND record_date >= #{startDate}
  AND record_date <= #{endDate}
